@echo off
chcp 65001 >nul
echo ========================================
echo    Clausidian 自动化安装脚本
echo ========================================
echo.

echo 正在检查 PowerShell 执行策略...
powershell -Command "Get-ExecutionPolicy" | findstr "Restricted" >nul
if %errorlevel% equ 0 (
    echo 检测到受限执行策略，尝试设置...
    powershell -Command "Set-ExecutionPolicy -ExecutionPolicy RemoteSigned -Scope CurrentUser -Force"
)

echo.
echo 正在运行配置脚本...
echo 注意：安装过程可能需要管理员权限
echo.

powershell -ExecutionPolicy Bypass -File "%~dp0configure-clausidian.ps1"

echo.
echo ========================================
echo    安装完成！请查看上方说明
echo ========================================
echo.
pause

