input.content:
@echo off
chcp 65001 >nul
echo ========================================
echo    Claudian 配置测试脚本
echo ========================================
echo.

echo [1/4] 检查知识库路径...
if exist "E:\道友的宝贝\道友的宝贝\.obsidian" (
    echo ✓ 知识库存在: E:\道友的宝贝\道友的宝贝
) else (
    echo ✗ 知识库不存在
    goto :error
)

echo.
echo [2/4] 检查claudian插件目录...
if exist "E:\道友的宝贝\道友的宝贝\.obsidian\plugins\claudian\" (
    echo ✓ claudian插件目录存在
) else (
    echo ✗ claudian插件目录不存在
    goto :error
)

echo.
echo [3/4] 检查插件文件...
set "plugin_dir=E:\道友的宝贝\道友的宝贝\.obsidian\plugins\claudian"
if exist "%plugin_dir%\manifest.json" (
    echo ✓ manifest.json 存在
) else (
    echo ✗ manifest.json 不存在
)

if exist "%plugin_dir%\main.js" (
    echo ✓ main.js 存在
) else (
    echo ✗ main.js 不存在
)

if exist "%plugin_dir%\styles.css" (
    echo ✓ styles.css 存在
) else (
    echo ✗ styles.css 不存在
)

echo.
echo [4/4] 检查community-plugins.json...
findstr "claudian" "E:\道友的宝贝\道友的宝贝\.obsidian\community-plugins.json" >nul
if %errorlevel% equ 0 (
    echo ✓ claudian 已在插件列表中
) else (
    echo ✗ claudian 不在插件列表中
)

echo.
echo ========================================
echo     配置测试完成
echo ========================================
echo.
echo 下一步操作：
echo 1. 下载完整插件文件从：https://github.com/YishenTu/claudian/releases
echo 2. 替换占位符文件
echo 3. 运行 设置API环境变量.bat 配置API密钥
echo 4. 重启Obsidian并测试
echo.
pause
exit /b 0

:error
echo.
echo ========================================
echo     配置存在问题
echo ========================================
echo 请检查：
echo 1. 知识库路径是否正确
echo 2. 是否运行了安装脚本
echo.
pause
exit /b 1

